import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface InterviewInputs {
  companyInfo: string;
  jobDescription: string;
  workExperience: string;
}

export interface InterviewResult {
  content: string;
}

import { GoogleGenAI } from "@google/genai";
import { SYSTEM_PROMPT } from "../constants";
import { InterviewInputs } from "../types";

export const generateInterviewQuestions = async (inputs: InterviewInputs): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const userPrompt = `
Here is the intake information for my final round interview prep:

A) Company name + company website link:
${inputs.companyInfo}

B) Full job description text:
${inputs.jobDescription}

C) Candidate resume: Work Experience section:
${inputs.workExperience}

Please design the elite, final-round interview questions based on this information as per the SYSTEM instructions.
`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: userPrompt,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.7,
        topK: 64,
        topP: 0.95,
      },
    });

    return response.text || "Failed to generate interview questions. Please try again.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("The AI service encountered an error. Check your inputs or API key configuration.");
  }
};

import React, { useState } from 'react';
import { InterviewInputs } from '../types';

interface InterviewFormProps {
  onSubmit: (inputs: InterviewInputs) => void;
  isLoading: boolean;
}

const InterviewForm: React.FC<InterviewFormProps> = ({ onSubmit, isLoading }) => {
  const [formData, setFormData] = useState<InterviewInputs>({
    companyInfo: '',
    jobDescription: '',
    workExperience: ''
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const isFormValid = formData.companyInfo && formData.jobDescription && formData.workExperience;

  return (
    <div className="bg-white rounded-xl shadow-md p-8 border border-slate-200">
      <h2 className="text-2xl font-bold text-slate-800 mb-6 flex items-center">
        <span className="bg-indigo-100 text-indigo-700 p-2 rounded-full mr-3 text-sm">Step 1</span>
        Interview Context
      </h2>

      <div className="space-y-6">
        <div>
          <label htmlFor="companyInfo" className="block text-sm font-semibold text-slate-700 mb-2">
            Company Name + Website Link
          </label>
          <input
            type="text"
            id="companyInfo"
            name="companyInfo"
            value={formData.companyInfo}
            onChange={handleChange}
            placeholder="e.g. OpenAI - https://openai.com"
            className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all outline-none"
          />
        </div>

        <div>
          <label htmlFor="jobDescription" className="block text-sm font-semibold text-slate-700 mb-2">
            Full Job Description
          </label>
          <textarea
            id="jobDescription"
            name="jobDescription"
            rows={5}
            value={formData.jobDescription}
            onChange={handleChange}
            placeholder="Paste the requirements, responsibilities, and success metrics..."
            className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all outline-none resize-none"
          />
        </div>

        <div>
          <label htmlFor="workExperience" className="block text-sm font-semibold text-slate-700 mb-2">
            Work Experience (Resume Section)
          </label>
          <textarea
            id="workExperience"
            name="workExperience"
            rows={8}
            value={formData.workExperience}
            onChange={handleChange}
            placeholder="Paste your roles, bullets, and outcomes/metrics..."
            className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all outline-none resize-none"
          />
