          className={`w-full py-4 px-6 rounded-lg font-bold text-white shadow-lg transition-all transform active:scale-95 flex items-center justify-center space-x-2 ${
            !isFormValid || isLoading 
              ? 'bg-slate-300 cursor-not-allowed' 
              : 'bg-indigo-600 hover:bg-indigo-700 hover:shadow-indigo-200'
          }`}
        >
          {isLoading ? (
            <>
              <svg className="animate-spin h-5 w-5 mr-3 text-white" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              <span>Analyzing Architecture...</span>
            </>
          ) : (
            <>
              <span>Generate Elite Interview Set</span>
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M10.293 3.293a1 1 0 011.414 0l6 6a1 1 0 010 1.414l-6 6a1 1 0 01-1.414-1.414L14.586 11H3a1 1 0 110-2h11.586l-4.293-4.293a1 1 0 010-1.414z" clipRule="evenodd" />
              </svg>
            </>
          )}
        </button>
      </div>
    </div>
  );
};

export default InterviewForm;

import React from 'react';

interface InterviewResultsProps {
  content: string;
  onReset: () => void;
}

const InterviewResults: React.FC<InterviewResultsProps> = ({ content, onReset }) => {
  // Parsing simple Markdown-like structure usually returned by Gemini
  // In a real app we might use react-markdown, but we'll use a clean layout here
  const sections = content.split('\n\n');

  return (
    <div className="bg-white rounded-xl shadow-md p-8 border border-slate-200 animate-fadeIn">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 border-b border-slate-100 pb-4 space-y-4 md:space-y-0">
        <div>
          <h2 className="text-3xl font-extrabold text-slate-900">Elite Strategy Guide</h2>
          <p className="text-slate-500 font-medium">Final-Round Readiness Analysis</p>
        </div>
        <button
          onClick={onReset}
          className="px-4 py-2 text-sm font-semibold text-slate-600 border border-slate-300 rounded-lg hover:bg-slate-50 transition-colors"
        >
          Generate New Set
        </button>
      </div>

      <div className="prose prose-slate max-w-none">
        {sections.map((section, idx) => {
          if (section.startsWith('1)') || section.startsWith('2)') || section.startsWith('3)')) {
            return (
              <div key={idx} className="mb-8 last:mb-0">
                <h3 className="text-xl font-bold text-indigo-700 mb-4 border-l-4 border-indigo-600 pl-4">
                  {section.split('\n')[0]}
                </h3>
                <div className="bg-slate-50 p-6 rounded-xl border border-slate-100 whitespace-pre-wrap leading-relaxed text-slate-700">
                  {section.split('\n').slice(1).join('\n')}
                </div>
              </div>
            );
          }

          if (section.toLowerCase().includes('out-of-the-box')) {
            return (
              <div key={idx} className="mt-12 bg-indigo-900 text-white p-8 rounded-2xl shadow-xl overflow-hidden relative">
                <div className="absolute top-0 right-0 -mt-4 -mr-4 w-24 h-24 bg-indigo-500 rounded-full opacity-20 blur-2xl"></div>
                <h3 className="text-2xl font-bold mb-6 flex items-center">
                   <span className="mr-3">🚀</span> Out-of-the-Box Signals
                </h3>
                <div className="whitespace-pre-wrap space-y-4 font-light text-indigo-100 leading-relaxed">
                  {section}
                </div>
              </div>
            );
          }

          return (
            <div key={idx} className="mb-4 whitespace-pre-wrap text-slate-700 leading-relaxed">
              {section}
            </div>
          );
        })}
      </div>

      <div className="mt-12 pt-8 border-t border-slate-100 text-center text-slate-400 text-sm">
        <p>© EnkiduZ Interview Architect • Domain Accuracy & calibration SME Validated</p>
      </div>
    </div>
  );
};

export default InterviewResults;

import React, { useState, useCallback } from 'react';
import Header from './components/Header';
import InterviewForm from './components/InterviewForm';
import InterviewResults from './components/InterviewResults';
import { generateInterviewQuestions } from './services/geminiService';
import { InterviewInputs } from './types';

